40	inline auto pick_free_port() -> uint16_t
41	{
42	  const int s = ::socket(AF_INET, SOCK_STREAM, 0);
43	  if (s < 0)
44	    throw std::runtime_error("pick_free_port: socket");
45	
46	  sockaddr_in addr{};
47	  addr.sin_family      = AF_INET;
48	  addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
49	  addr.sin_port        = 0;
50	
51	  if (::bind(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) < 0) {
52	    ::close(s);
53	    throw std::runtime_error("pick_free_port: bind");
54	  }
55	  socklen_t len = sizeof(addr);
56	  if (::getsockname(s, reinterpret_cast<sockaddr*>(&addr), &len) < 0) {
57	    ::close(s);
58	    throw std::runtime_error("pick_free_port: getsockname");
59	  }
60	  ::close(s);
61	  return ntohs(addr.sin_port);
62	}
